    assert agent_event_steps["usage_neighborhood"]["status"] == "skipped"
    assert agent_event_steps["graphrag_packet"]["status"] == "skipped"

    applied = module.performance_baseline(
        aoa_root=aoa_root,
        anchor="aoa-kag-mcp",
        kind="mcp",
        limit=2,
        per_route_limit=3,
        search_target="latest",
        max_raw_bytes=1,
        apply_refresh=True,
        refresh_budget_seconds=30,
        write_report=True,
    )
