    assert conn.execute(
        """
        SELECT COUNT(*)
        FROM document_routes JOIN route_terms ON route_terms.id = document_routes.route_id
        WHERE route_terms.layer = ? AND route_terms.key = ?
        """,
        ("scope_contract", "analysis_only"),
    ).fetchone()[0] > 0
