def test_search_shards_dirty_only_limit_applies_after_dirty_filter(tmp_path: Path, monkeypatch: Any) -> None:
    aoa_root = tmp_path / ".aoa"
    shard = "month/2026-05"
    module.search_shard_db_path(aoa_root, shard).parent.mkdir(parents=True)
    module.search_shard_db_path(aoa_root, shard).touch()
    records = [
        {"session_id": f"may-{idx}", "session_label": f"2026-05-{idx + 1:02d}__001__dirty-{idx}"}
        for idx in range(5)
    ] + [
        {"session_id": "june-1", "session_label": "2026-06-01__001__other-shard"}
    ]
    calls: dict[str, Any] = {}

    def fake_records(_aoa_root: Path, *, target: str, since: str | None, until: str | None, limit: int | None) -> list[dict[str, Any]]:
        calls["record_limit"] = limit
        return list(records)

    def fake_dirty_filter(
        _aoa_root: Path,
        selected_records: list[dict[str, Any]],
        *,
        shard: str | None = None,
        include_deferred_live: bool = False,
    ) -> tuple[list[dict[str, Any]], dict[str, Any]]:
        dirty_records = [
            item for item in selected_records
            if module.search_shard_key_for_record(item) == "month/2026-05"
        ]
        return dirty_records, {
            "dirty_candidate_count": len(dirty_records),
            "deferred_live_skipped_count": 0,
            "pre_filter_selected_count": len(selected_records),
            "dirty_selected_count": len(dirty_records),
            "skipped_current_count": len(selected_records) - len(dirty_records),
        }

    def fake_search_index_sessions(**kwargs: Any) -> dict[str, Any]:
        selected_records = kwargs["selected_records"]
        calls["selected_labels"] = [item["session_label"] for item in selected_records]
        return {
            "ok": True,
            "processed_count": len(selected_records),
            "document_count": len(selected_records),
            "session_document_count": len(selected_records),
            "segment_document_count": 0,
            "event_document_count": 0,
            "incident_document_count": 0,
            "goal_lifecycle_document_count": 0,
            "task_episode_document_count": 0,
            "slow_sessions": [],
            "slow_session_warning_count": 0,
            "diagnostics": [],
        }

    monkeypatch.setattr(module, "search_records_for_target", fake_records)
    monkeypatch.setattr(module, "filter_search_records_to_dirty_shard_sessions", fake_dirty_filter)
    monkeypatch.setattr(module, "search_index_sessions", fake_search_index_sessions)
    monkeypatch.setattr(module, "build_search_catalog", lambda *_args, **_kwargs: {"ok": True, "status": "current"})

    result = module.materialize_search_shards(
        aoa_root=aoa_root,
        target="all",
        shard=shard,
        rebuild_shards=False,
        dirty_only=True,
        limit=3,
    )

    assert result["ok"] is True
    assert calls["record_limit"] is None
    assert len(calls["selected_labels"]) == 3
    assert calls["selected_labels"] == [item["session_label"] for item in records[:3]]
    assert result["selected_count"] == 3
    assert result["dirty_selected_count"] == 5
    assert result["dirty_pre_limit_selected_count"] == 5
    assert result["dirty_limit"] == 3
    assert result["dirty_limited_count"] == 3


def test_search_sqlite_compact_plans_and_stages_verified_copy(tmp_path: Path) -> None:
    aoa_root = tmp_path / ".aoa"
    db_path = module.search_db_path(aoa_root)
    db_path.parent.mkdir(parents=True)
    conn = sqlite3.connect(str(db_path))
    conn.execute("CREATE TABLE documents (id INTEGER PRIMARY KEY, body TEXT)")
    conn.execute("INSERT INTO documents (body) VALUES (?)", ("search body",))
    conn.commit()
    conn.close()

    parser = module.build_parser()
    args = parser.parse_args(["search-sqlite-compact", "--method", "vacuum-into"])
    assert args.func is module.command_search_sqlite_compact

    dry_run = module.search_sqlite_compact(aoa_root=aoa_root)
    assert dry_run["artifact_type"] == "session_memory_search_sqlite_compact"
    assert dry_run["ok"] is True
    assert dry_run["mutates"] is False
    assert dry_run["method"] == "vacuum-into"
    assert dry_run["execution_profile"] == module.SEARCH_SQLITE_COMPACT_EXECUTION_PROFILE
    assert dry_run["store_path"] == str(db_path)
    assert dry_run["target_path_explicit"] is False
    assert "generated portable SQLite search projection" in dry_run["stop_line"]

    missing_target = module.search_sqlite_compact(aoa_root=aoa_root, apply=True)
    assert missing_target["ok"] is False
    assert "vacuum_into_target_path_required" in missing_target["diagnostics"]
    assert missing_target["mutates"] is False

    target = tmp_path / "search-compact.sqlite3"
    applied = module.search_sqlite_compact(
        aoa_root=aoa_root,
        apply=True,
        target_path=target,
        write_report=True,
    )
    assert applied["ok"] is True
    assert applied["mutates"] is True
    assert applied["action"]["integrity_check"]["ok"] is True
    assert target.exists()
    assert Path(applied["report_json"]).exists()
    assert Path(applied["report_markdown"]).exists()

    args = parser.parse_args(["search-sqlite-compact", "--promote-copy", "--delete-backup-after-verify"])
    assert args.promote_copy is True
    assert args.delete_backup_after_verify is True

    promote_target = tmp_path / "search-promote-copy.sqlite3"
    backup_path = tmp_path / "search-before-promote.sqlite3"
    promoted = module.search_sqlite_compact(
        aoa_root=aoa_root,
        apply=True,
        target_path=promote_target,
        backup_path=backup_path,
        promote_copy=True,
        write_report=True,
    )
    assert promoted["ok"] is True
    assert promoted["mutates"] is True
    assert promoted["status"] == "promoted_backup_retained"
    assert promoted["promote_copy"] is True
    assert promoted["backup_path"] == str(backup_path)
    assert promoted["action"]["promotion"]["ok"] is True
    assert promoted["action"]["promotion"]["backup_retained"] is True
    assert promoted["action"]["promotion"]["live_integrity_check"]["ok"] is True
    assert backup_path.exists()
    assert not promote_target.exists()
    assert db_path.exists()
    conn = sqlite3.connect(str(db_path))
    try:
        assert conn.execute("SELECT COUNT(*) FROM documents").fetchone()[0] == 1
    finally:
        conn.close()


